/**
 * Provides previews for selecting/moving/resizing shapes when creating/removing space.
 *
 */
export default class SpaceToolPreview {
    static $inject: string[];
    /**
     * @param eventBus
     * @param elementRegistry
     * @param canvas
     * @param styles
     */
    constructor(
      eventBus: EventBus,
      elementRegistry: ElementRegistry,
      canvas: Canvas,
      styles: Styles
    );
}

type Canvas = import("../../core/Canvas.js").default;
type ElementRegistry = import("../../core/ElementRegistry.js").default;
type EventBus = import("../../core/EventBus.js").default;
type Styles = import("../../draw/Styles.js").default;